customEChartConfig:
{{ ((chartType) => ( 
(() => {

  const data = GetOpenActions.data;

  if (!data || data.length === 0) {
    return {
      option: {
        title: {
          text: "No Open Actions",
          left: "center"
        }
      }
    };
  }

  // 🔹 Group by PO
  const grouped = {};

  data.forEach(r => {

    const po = r.MicrossSalesOrderReference;

    if (!po) return; // 🔴 skip bad rows

    if (!grouped[po]) {
      grouped[po] = 0;
    }

    grouped[po] += 1;

  });

  const xData = Object.keys(grouped);
  const yData = Object.values(grouped);

  return {
    option: {
      tooltip: { trigger: 'axis' },
      xAxis: {
        type: 'category',
        data: xData
      },
      yAxis: {
        type: 'value'
      },
      series: [
        {
          type: 'bar',
          data: yData,
          itemStyle: {
            color: '#ff4d4f'
          }
        }
      ]
    }
  };

})()
))(Chart_OpenActions.chartType) }}
